function ps_json($s,$m='',$x=array()){header('Content-Type: application/json');$p=array('status'=>$s);if($m!=='')$p['error_message']=$m;foreach($x as $k=>$v)$p[$k]=$v;echo json_encode($p);exit;}
function ps_h($v){return htmlspecialchars((string)$v,ENT_QUOTES,'UTF-8');}
function ps_num($v,$d=5){return number_format((float)$v,$d,',','.');}
function ps_dt($v){$v=trim((string)$v);if($v==='')return null;return str_replace('T',' ',$v).(strlen($v)===16?':00':'');}
function ps_next_no($date){global $db;$prefix='PSC'.date('Ym',strtotime($date));$r=$db->fetch("SELECT schedule_no FROM erp_production_schedule WHERE schedule_no LIKE ? ORDER BY schedule_no DESC LIMIT 1",array($prefix.'%'));$n=1;if($r&&preg_match('/(\d{5})$/',$r->schedule_no,$m))$n=(int)$m[1]+1;return $prefix.sprintf('%05d',$n);}
