    $res=array();foreach($rows as $r)$res[]=array('id'=>$r->id_production_order,'text'=>$r->no_production_order.' | '.$r->material_code.' - '.$r->material_name.' | Qty '.ps_num($r->order_qty).' '.$r->uom.' | '.$r->op_count.' op','start_date'=>$r->start_date,'finish_date'=>$r->finish_date,'plant'=>$r->plant,'priority'=>$r->priority);
