    $shifts=$db->query("SELECT id,kode_shift,nama_shift FROM erp_shift WHERE status='Aktif' ORDER BY kode_shift");$shiftOptions='<option value="">-</option>';foreach($shifts as $s)$shiftOptions.='<option value="'.(int)$s->id.'" data-code="'.ps_h($s->kode_shift).'">'.ps_h($s->kode_shift.' - '.$s->nama_shift).'</option>';
    $seq=1;foreach($ops as $o){$dur=max(30,(float)$o->setup_time+(float)$o->machine_time+(float)$o->labor_time);$s=date('Y-m-d\TH:i',$cursor);$cursor+=((int)$dur)*60;$f=date('Y-m-d\TH:i',$cursor);echo '<tr><td>'.(int)$seq.'<input type="hidden" name="op_id[]" value="'.(int)$o->id_operation.'"><input type="hidden" name="sequence_no['.(int)$o->id_operation.']" value="'.(int)$seq.'"></td><td><strong>'.ps_h($o->operation_no).'</strong><br><small>'.ps_h($o->operation_name).'</small></td><td><input name="work_center['.(int)$o->id_operation.']" class="form-control" value="'.ps_h($o->work_center).'"><small>'.ps_h($o->work_center?:'-').'</small></td><td><select name="shift_id['.(int)$o->id_operation.']" class="form-control ps-shift">'.$shiftOptions.'</select></td><td><input type="datetime-local" name="op_start['.(int)$o->id_operation.']" class="form-control ps-op-start" value="'.$s.'"></td><td><input type="datetime-local" name="op_finish['.(int)$o->id_operation.']" class="form-control ps-op-finish" value="'.$f.'"></td><td><input type="number" step="1" name="duration['.(int)$o->id_operation.']" class="form-control text-right" value="'.ps_h($dur).'"></td><td><input type="number" step="0.00001" name="scheduled_qty['.(int)$o->id_operation.']" class="form-control text-right" value="'.ps_h($po->order_qty).'"></td><td><input name="op_remarks['.(int)$o->id_operation.']" class="form-control"></td></tr>';$seq++;}
